 1→import Card from '@/components/ui/Card';
 2→import Badge from '@/components/ui/Badge';
 3→
 4→interface LoyaltyCardProps {
 5→  programName: string;
 6→  type: 'stamp' | 'points';
 7→  balance: number;
 8→  target: number;
 9→  tier: string;
10→}
11→
12→export default function LoyaltyCard({ programName, type, balance, target, tier }: LoyaltyCardProps) {
13→  const progress = Math.min(100, (balance / target) * 100);
14→  const tierVariant = tier === 'vip' ? 'accent' : tier === 'gold' ? 'warning' : tier === 'silver' ? 'blue' : 'default';
15→
16→  return (
17→    <Card hover className="space-y-3">
18→      <div className="flex items-center justify-between">
19→        <h3 className="text-[15px] font-semibold text-[var(--text-primary)]">{programName}</h3>
20→        <Badge variant={tierVariant}>{tier.toUpperCase()}</Badge>
21→      </div>
22→
23→      <div className="space-y-1.5">
24→        <div className="flex justify-between text-[13px]">
25→          <span className="text-[var(--text-secondary)]">{balance} / {target} {type === 'stamp' ? 'tampons' : 'points'}</span>
26→          <span className="font-medium text-[var(--accent)]">{Math.round(progress)}%</span>
27→        </div>
28→        <div className="h-2 w-full rounded-full bg-[var(--bg-elevated)] overflow-hidden">
29→          <div className="h-full bg-[var(--accent)] rounded-full transition-all duration-500" style={{ width: `${progress}%` }} />
30→        </div>
31→      </div>
32→    </Card>
33→  );
34→}
