 1→import { createServerSupabase } from '@/lib/supabase/server';
 2→import LoyaltyCard from '@/components/customer/LoyaltyCard';
 3→
 4→export default async function CustomerDashboard() {
 5→  const supabase = await createServerSupabase();
 6→  const { data: { user } } = await supabase.auth.getUser();
 7→
 8→  const { data: cards } = await supabase
 9→    .from('customer_cards')
10→    .select('*, loyalty_programs(*)')
11→    .eq('customer_id', user!.id);
12→
13→  return (
14→    <div className="space-y-4 py-4">
15→      <h1 className="text-xl font-bold text-[var(--text-primary)]">Mes cartes fidelite</h1>
16→
17→      {cards && cards.length > 0 ? (
18→        cards.map((card: any, i: number) => (
19→          <div key={card.id} className={`stagger-enter stagger-${Math.min(i + 1, 6)}`}>
20→            <LoyaltyCard
21→              programName={card.loyalty_programs.name}
22→              type={card.loyalty_programs.type}
23→              balance={card.balance}
24→              target={card.loyalty_programs.target}
25→              tier={card.tier}
26→            />
27→          </div>
28→        ))
29→      ) : (
30→        <div className="text-center py-12 text-[var(--text-tertiary)]">
31→          <p>Aucune carte. Scannez un QR code pour commencer !</p>
32→        </div>
33→      )}
34→    </div>
35→  );
36→}
