 1→import { createServerSupabase } from '@/lib/supabase/server';
 2→import { redirect } from 'next/navigation';
 3→import ScanHandler from './scan-handler';
 4→
 5→export default async function ScanPage({ params }: { params: Promise<{ qr_id: string }> }) {
 6→  const { qr_id } = await params;
 7→  const supabase = await createServerSupabase();
 8→
 9→  // Fetch QR code info
10→  const { data: qrCode } = await supabase
11→    .from('merchant_qr_codes')
12→    .select('*, loyalty_programs(*, merchants(business_name))')
13→    .eq('id', qr_id)
14→    .eq('is_active', true)
15→    .single();
16→
17→  if (!qrCode) {
18→    return (
19→      <div className="min-h-screen flex items-center justify-center bg-[var(--bg-base)]">
20→        <p className="text-[var(--error)]">QR code invalide ou expire.</p>
21→      </div>
22→    );
23→  }
24→
25→  // Check if user is logged in
26→  const { data: { user } } = await supabase.auth.getUser();
27→
28→  if (!user) {
29→    redirect(`/login?redirect=/scan/${qr_id}`);
30→  }
31→
32→  return <ScanHandler qrCode={qrCode} userId={user.id} />;
33→}
