 6→interface ButtonProps {
 7→  children: ReactNode;
 8→  variant?: 'primary' | 'secondary' | 'ghost' | 'danger';
 9→  size?: 'sm' | 'md' | 'lg';
10→  icon?: React.ElementType;
11→  iconPosition?: 'left' | 'right';
12→  loading?: boolean;
13→  disabled?: boolean;
14→  onClick?: () => void;
15→  className?: string;
16→  type?: 'button' | 'submit' | 'reset';
17→}
18→
19→const VARIANT = {
20→  primary: 'bg-[var(--accent)] text-white font-medium hover:bg-[var(--accent-hover)] active:opacity-90 disabled:opacity-50',
21→  secondary: 'bg-transparent text-[var(--text-secondary)] border border-[var(--border-default)] hover:border-[var(--border-strong)] hover:text-[var(--text-primary)]',
22→  ghost: 'bg-transparent text-[var(--text-secondary)] hover:bg-[var(--glass-active)] hover:text-[var(--text-primary)]',
23→  danger: 'bg-transparent text-[var(--error)] border border-[var(--error)]/20 hover:bg-[var(--error-subtle)]',
24→};
25→
26→const SIZE = {
27→  sm: 'text-[13px] px-3 py-1.5 rounded-lg gap-1.5',
28→  md: 'text-sm px-4 py-2 rounded-lg gap-2',
29→  lg: 'text-sm px-5 py-2.5 rounded-lg gap-2',
30→};
31→
32→const Spinner = () => (
33→  <svg className="animate-spin w-4 h-4" viewBox="0 0 24 24" fill="none">
34→    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" />
35→    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
36→  </svg>
37→);
38→
39→export default function Button({
40→  children, variant = 'primary', size = 'md', icon: Icon,
41→  iconPosition = 'left', loading = false, disabled = false,
42→  onClick, className = '', type = 'button',
43→}: ButtonProps) {
44→  return (
45→    <button
46→      type={type}
47→      onClick={onClick}
48→      disabled={disabled || loading}
49→      className={cn(
50→        'inline-flex items-center justify-center font-medium transition-all duration-150 press-effect',
51→        disabled || loading ? 'cursor-not-allowed' : 'cursor-pointer',
52→        VARIANT[variant], SIZE[size], className,
53→      )}
54→    >
55→      {loading && <Spinner />}
56→      {!loading && Icon && iconPosition === 'left' && <Icon className="w-4 h-4" />}
57→      <span className={loading ? 'opacity-70' : ''}>{children}</span>
58→      {!loading && Icon && iconPosition === 'right' && <Icon className="w-4 h-4" />}
59→    </button>
60→  );
61→}
